parameters.jsCode:
const nodes = [
  { key: 'resource', name: 'Result Recursos', bc: 'BC API - Recursos' },
  { key: 'ps_year', name: 'Result PS_Years', bc: 'BC API - PS_Years' },
  { key: 'job', name: 'Result Proyectos', bc: 'BC API - Proyectos' },
  { key: 'job_team', name: 'Result Equipo Proyectos', bc: 'BC API - Equipo Proyectos' },
  { key: 'job_task', name: 'Result Job Task', bc: 'BC API - ProyectosTareas' },
  { key: 'centers_of_responsibility', name: 'Result CentrosDeResponsabilidad', bc: 'BC API - CentrosDeResponsabilidad' },
  { key: 'user_configuration', name: 'Result ConfiguracionUsuarios', bc: 'BC API - ConfiguracionUsuarios' },
  { key: 'technologies', name: 'Result Tecnologias', bc: 'BC API - Tecnologias' },
  { key: 'typologies', name: 'Result Tipologias', bc: 'BC API - Tipologias' },
  { key: 'departments', name: 'Result Departamentos', bc: 'BC API - Departamentos' },
  { key: 'job_ledger_entry_month', name: 'Result MovimientosProyectos', bc: 'BC API - MovimientosProyectos' },
  { key: 'job_planning_line', name: 'Result PlanificacionMes', bc: 'BC API - PlanificacionMes' },
  { key: 'expediente_mes', name: 'Result ExpedienteMes', bc: 'BC API - ExpedienteMes' },
  { key: 'meses_cerrados', name: 'Result MesesCerrados', bc: 'BC API - MesesCerrados' },
  { key: 'objectives_by_department', name: 'Result ObjectivesByDepartaments', bc: 'BC API - ObjectivesByDepartaments' },
  { key: 'historico_planificacion_mes', name: 'Result HistoricoPlanificacionMes', bc: 'BC API - HistoricoPlanificacionMes' },
  { key: 'dias_imputacion', name: 'Result DiasImputacion', bc: 'BC API - DiasImputacion' },
];
function bcHadError(bcItems) {
  for (const it of bcItems) {
    const j = it?.json || {};
    if (j.error) return String(typeof j.error === 'object' ? (j.error.message || JSON.stringify(j.error)) : j.error);
    const code = Number(j.statusCode || j?.response?.statusCode || 0);
    if (code >= 400) return j?.body?.error?.message || ('HTTP ' + code);
  }
  return null;
}
const details = {};
let success = 0, failed = 0;
for (const n of nodes) {
  let arr = [];
  try { arr = $items(n.name).map(i => i.json).filter(Boolean); } catch (e) { arr = []; }
  if (arr.length > 0) {
    const d = arr[0];
    const entry = { status: d.status };
    if (typeof d.synced !== 'undefined') entry.synced = d.synced;
    if (typeof d.success !== 'undefined') entry.success = d.success;
    if (typeof d.failed !== 'undefined') entry.failed = d.failed;
    if (d.message) entry.message = String(d.message);
    if (d.causeNode) entry.causeNode = d.causeNode;
    details[n.key] = entry;
    if (String(d.status) === 'ok') success++;
    else if (String(d.status) === 'skipped') { /* no-op */ }
    else failed++;
    continue;
  }
  // Result no corrió (p.ej. Transform vació → Upsert sin items). Inferir desde BC API.
  if (n.bc) {
    let bcItems = [];
    try { bcItems = $items(n.bc); } catch (e) { bcItems = []; }
    if (bcItems.length) {
      const errMsg = bcHadError(bcItems);
      if (errMsg) {
        details[n.key] = { status: 'error', synced: 0, failed: 1, message: errMsg, causeNode: n.bc };
        failed++;
      } else {
        details[n.key] = { status: 'ok', synced: 0, success: 0, empty: true, causeNode: n.bc };
        success++;
      }
    }
  }
}
const overall = failed === 0 ? 'ok' : (success > 0 ? 'partial_error' : 'error');
const company = ($('Resolve Company').first()?.json?.companyName) || '';
const mutexExecutionId = $('Parse Mutex Result').first()?.json?.mutexExecutionId ?? null;
if (!mutexExecutionId) {
  throw new Error('004: mutexExecutionId missing in Compute Execution Summary');
}
return [{ json: { status: overall, timestamp: new Date().toISOString(), company, summary: { total_entities: Object.keys(details).length, success, failed }, details, mutexExecutionId } }];

// Resultado por entidad: Recursos
const items = $input.all();
let failed = 0;
let firstErr = '';
for (const it of items) {
  const j = it?.json || {};
  const statusCode = Number(j?.statusCode ?? j?.response?.statusCode ?? 0);
  const bodyErr = j?.body?.error?.message || (typeof j?.body === 'string' ? j.body : null);
  const msg = j?.error?.message || j?.message || j?.data?.error || j?.response?.body || j?.responseBody || bodyErr || null;
  if (!firstErr && msg) firstErr = String(msg);
  if (msg || statusCode >= 400) failed++;
}
const success = items.length - failed;
const synced = success;
const res = { key: 'recursos', causeNode: 'Upsert Recursos' };
if (failed > 0) { res.status = 'error'; res.synced = success; res.failed = failed; res.message = firstErr || ('HTTP ' + (items[0]?.json?.statusCode || 'error')); } else { res.status = 'ok'; res.synced = synced; res.success = success; }
return [{ json: res }];

// Resultado por entidad: PS_Years
const items = $input.all();
let failed = 0;
let firstErr = '';
for (const it of items) {
  const j = it?.json || {};
  const statusCode = Number(j?.statusCode ?? j?.response?.statusCode ?? 0);
  const bodyErr = j?.body?.error?.message || (typeof j?.body === 'string' ? j.body : null);
  const msg = j?.error?.message || j?.message || j?.data?.error || j?.response?.body || j?.responseBody || bodyErr || null;
  if (!firstErr && msg) firstErr = String(msg);
  if (msg || statusCode >= 400) failed++;
}
const success = items.length - failed;
const synced = success;
const res = { key: 'ps_year', causeNode: 'Upsert PS_Year' };
if (failed > 0) { res.status = 'error'; res.synced = success; res.failed = failed; res.message = firstErr || ('HTTP ' + (items[0]?.json?.statusCode || 'error')); } else { res.status = 'ok'; res.synced = synced; res.success = success; }
return [{ json: res }];

// Resultado por entidad: Proyectos
const items = $input.all();
let failed = 0;
let firstErr = '';
for (const it of items) {
  const j = it?.json || {};
  const statusCode = Number(j?.statusCode ?? j?.response?.statusCode ?? 0);
  const bodyErr = j?.body?.error?.message || (typeof j?.body === 'string' ? j.body : null);
  const msg = j?.error?.message || j?.message || j?.data?.error || j?.response?.body || j?.responseBody || bodyErr || null;
  if (!firstErr && msg) firstErr = String(msg);
  if (msg || statusCode >= 400) failed++;
}
const success = items.length - failed;
const synced = success;
const res = { key: 'proyectos', causeNode: 'Upsert Proyectos' };
if (failed > 0) { res.status = 'error'; res.synced = success; res.failed = failed; res.message = firstErr || ('HTTP ' + (items[0]?.json?.statusCode || 'error')); } else { res.status = 'ok'; res.synced = synced; res.success = success; }
return [{ json: res }];

// Resultado por entidad: Equipo Proyectos
const items = $input.all();
let failed = 0;
let firstErr = '';
for (const it of items) {
  const j = it?.json || {};
  const statusCode = Number(j?.statusCode ?? j?.response?.statusCode ?? 0);
  const bodyErr = j?.body?.error?.message || (typeof j?.body === 'string' ? j.body : null);
  const msg = j?.error?.message || j?.message || j?.data?.error || j?.response?.body || j?.responseBody || bodyErr || null;
  if (!firstErr && msg) firstErr = String(msg);
  if (msg || statusCode >= 400) failed++;
}
const success = items.length - failed;
const synced = success;
const res = { key: 'equipo_proyectos', causeNode: 'Upsert Equipo Proyectos' };
if (failed > 0) { res.status = 'error'; res.synced = success; res.failed = failed; res.message = firstErr || ('HTTP ' + (items[0]?.json?.statusCode || 'error')); } else { res.status = 'ok'; res.synced = synced; res.success = success; }
return [{ json: res }];

// Construye el email de alerta cuando el sync 004 termina con error/partial_error
const d = $json.details ? $json : ($('Compute Execution Summary').first()?.json || {});
const failedEntities = Object.entries(d.details || {})
  .filter(([, v]) => String(v?.status) !== 'ok')
  .map(([key, v]) => ({ key, message: String(v?.message || v?.causeNode || 'Error desconocido') }));

const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const rows = failedEntities
  .map((f) => `<tr><td style="padding:6px;border:1px solid #ddd;">${esc(f.key)}</td><td style="padding:6px;border:1px solid #ddd;">${esc(f.message)}</td></tr>`)
  .join('');

const html = `<!DOCTYPE html><html><body style="font-family:Segoe UI,sans-serif;color:#333;">` +
  `<p style="margin:0 0 16px;font-size:13px;color:#c0392b;font-weight:600;">Alerta de sincronizacion BC - Workflow 004 (Analytics)</p>` +
  `<p>La sincronizacion de <strong>${esc(d.company || '(sin empresa)')}</strong> ha finalizado con estado <strong>${esc(d.status)}</strong>.</p>` +
  `<p>Entidades: ${d.summary?.success ?? 0} OK / ${d.summary?.failed ?? 0} con error (total ${d.summary?.total_entities ?? 0}).</p>` +
  `<table style="border-collapse:collapse;width:100%;max-width:720px;"><thead><tr style="background:#f0f0f0;">` +
  `<th style="padding:6px;border:1px solid #ddd;text-align:left;">Entidad</th><th style="padding:6px;border:1px solid #ddd;text-align:left;">Error</th></tr></thead>` +
  `<tbody>${rows}</tbody></table>` +
  `<p style="font-size:12px;color:#888;margin-top:16px;">Mensaje automatico - ver detalle completo en tabla sync_executions.</p>` +
  `</body></html>`;

const subjectPrefix = d.status === 'error' ? 'FALLO' : 'Aviso';

return [{
  json: {
    to: 'soporte@powersolution.es',
    subject: `[BC Sync 004] ${subjectPrefix} sincronizacion ${d.company || ''} - ${d.summary?.failed ?? 0} entidad(es) con error`,
    html
  }
}];

// Normaliza entrada y mapea a public.bc_resource (filtros alineados con workflow 001)
const input = $input.all();
if (input.length === 0) return [];

const raw = input[0]?.json ?? {};
const src = raw?.body ?? raw;
const registros = Array.isArray(src.value) ? src.value : (Array.isArray(src) ? src : [src]);
const items = [];

const cleanDate = (v) => {
  const s = String(v ?? '').trim();
  if (!s || s === '0001-01-01') return '';
  return s;
};
const toBool = (v) => {
  const s = String(v).toLowerCase();
  return s === 'true' || s === '1' || s === 't' || s === 'yes';
};

const companyName = $items('Build sync_state map')[0]?.json?.company || '';

for (const r of registros) {
  const code = String(r.no ?? r.code ?? '').trim();
  if (!code) continue;

  const name = String(r.name ?? '').trim();
  const email = String(r.email ?? r.arbvrneMail ?? '').trim();
  const departmentCode = String(
    r.globalDimension1Code ?? r.global_dimension1_code ?? r.department ?? r.department_code ?? ''
  ).trim();
  const calendarType = String(
    r.calendario ?? r.Calendario ?? r.calendar_type ?? r.calendarType ?? r.calendar ?? ''
  ).trim();
  const fechaDeBaja = cleanDate(r.fechaDeBaja ?? r.fecha_de_baja);
  const fechaDeAlta = cleanDate(r.fechaDeAlta ?? r.fecha_de_alta);
  const subcontratacion = (typeof r.subcontratacion === 'boolean') ? r.subcontratacion : toBool(r.subcontratacion);
  const perfil = String(r.perfil ?? '').trim();
  const lastModifiedDateTime = String(r.lastModifiedDateTime ?? r.last_modified_datetime ?? '').trim();

  if (!email || !email.includes('@')) {
    console.log(`⚠️ Recurso ${code} sin email válido - OMITIDO`);
    continue;
  }
  if (!departmentCode) {
    console.log(`⚠️ Recurso ${code} sin department - OMITIDO`);
    continue;
  }

  items.push({
    json: {
      companyName,
      code,
      name,
      email,
      departmentCode,
      calendarType,
      fechaDeBaja,
      fechaDeAlta,
      subcontratacion,
      perfil,
      lastModifiedDateTime,
    },
  });
}

console.log(`✅ Transform Recursos: ${items.length} recursos válidos de ${registros.length} totales`);
if (items.length === 0) {
  return [{ json: { _skip: true, reason: 'no_valid_resources' } }];
}
return items;

// Normaliza entrada y mapea a public.bc_ps_year
const input = $input.all();
if (input.length === 0) return [];

const raw = input[0]?.json ?? {};
const src = raw?.body ?? raw;
const registros = Array.isArray(src.value) ? src.value : (Array.isArray(src) ? src : [src]);
const items = [];

// Obtener companyName del nodo Build sync_state map
const companyName = $items('Build sync_state map')[0]?.json?.company || '';

for (const r of registros) {
  const psYear = String(r.year ?? r.Year ?? r.PS_Year ?? r.ps_year ?? '').trim();
  if (!psYear || psYear === '0') continue;

  items.push({
    json: {
      companyName,
      PS_Year: parseInt(psYear) || 0,
    },
  });
}

return items;

// Transform Proyectos — filtros alineados con workflow 001 Timesheet
const input = $input.all();
if (input.length === 0) return [];

const companyName = ($('Finalize Sync Context').first()?.json || $('Build sync_state map').first().json).company;
const data = input[0].json;
const proyectos = data.value || [];
const items = [];

const allowedStatus = new Set(['Planning','Quote','Open','Completed','Lost']);

const cleanDate = (v) => {
  const s = String(v ?? '').trim();
  if (!s || s === '0001-01-01') return '';
  return s;
};
const toBool = (v) => {
  const s = String(v).toLowerCase();
  return s === 'true' || s === '1' || s === 't' || s === 'yes';
};

let skipped = { total: 0, reasons: { pppy: 0, noDescription: 0, noDepartamento: 0, invalidStatus: 0 } };

for (const p of proyectos) {
  const no = String(p.no ?? '').trim();
  if (!no) continue;

  if (no.startsWith('PP') || no.startsWith('PY')) {
    skipped.total++;
    skipped.reasons.pppy++;
    continue;
  }

  const description = String(p.description ?? '').trim();
  const departamento = String(p.departamento ?? p.globalDimension1Code ?? '').trim();
  const statusRaw = String(p.estado ?? p.Estado ?? p.status ?? '').trim();

  if (!description) {
    skipped.total++;
    skipped.reasons.noDescription++;
    continue;
  }
  if (!departamento) {
    skipped.total++;
    skipped.reasons.noDepartamento++;
    continue;
  }
  if (!allowedStatus.has(statusRaw)) {
    skipped.total++;
    skipped.reasons.invalidStatus++;
    continue;
  }

  let probability = 0;
  const probValue = p.Probability ?? p.probability;
  if (probValue !== undefined && probValue !== null) {
    if (typeof probValue === 'string' && probValue.trim() === '') {
      probability = 0;
    } else {
      const num = Number(probValue);
      if (!isNaN(num) && isFinite(num)) probability = num;
    }
  }

  items.push({
    json: {
      companyName,
      no,
      description,
      departamento,
      probability,
      tipoProyecto: String(p.TipoProyecto ?? p.tipoProyecto ?? '').trim(),
      status: statusRaw,
      fechaFin: cleanDate(p.Fechafin ?? p.fechaFin ?? p.endingDate ?? ''),
      doNotConsolidate: (typeof p.DoNotConsolidate === 'boolean') ? p.DoNotConsolidate : toBool(p.DoNotConsolidate),
      responsible: String(p.Responsible ?? p.responsible ?? '').trim(),
      lastModifiedDateTime: String(p.lastModifiedDateTime ?? p.last_modified_datetime ?? '').trim(),
    },
  });
}

console.log(`✅ Transform Proyectos: ${items.length} proyectos válidos de ${proyectos.length} totales`);
if (skipped.total > 0) {
  console.log(`⚠️ Omitidos: ${skipped.total} (PP/PY=${skipped.reasons.pppy}, desc=${skipped.reasons.noDescription}, dept=${skipped.reasons.noDepartamento}, status=${skipped.reasons.invalidStatus})`);
}
if (items.length === 0) {
  return [{ json: { _skip: true, reason: 'no_valid_jobs' } }];
}
return items;

// Transform Equipo Proyectos — alineado con workflow 001
const input = $input.all();
if (input.length === 0) return [];

const raw = input[0]?.json ?? {};
const src = raw?.body ?? raw;
const registros = Array.isArray(src.value) ? src.value : (Array.isArray(src) ? src : [src]);
const items = [];
const companyName = $items('Build sync_state map')[0]?.json?.company || '';

for (const r of registros) {
  const jobNo = String(r.arbvrnJobNo ?? r.ARBVRNJobNo ?? r.job_no ?? r.jobNo ?? '').trim();
  const resourceNo = String(r.arbvrnResourceNo ?? r.ARBVRNResourceNo ?? r.resource_no ?? r.resourceNo ?? '').trim();
  const resourceName = String(r.arbvrnResourceName ?? r.ARBVRNResourceName ?? r.resource_name ?? '').trim();

  if (!jobNo || !resourceNo) continue;
  if (jobNo.startsWith('PP') || jobNo.startsWith('PY')) continue;

  items.push({ json: { companyName, jobNo, resourceNo, resourceName } });
}

console.log(`✅ Transform Equipo Proyectos: ${items.length} miembros de ${registros.length} totales`);
if (items.length === 0) {
  return [{ json: { _skip: true, reason: 'no_valid_team_members' } }];
}
return items;

const upsertNode = 'Upsert Recursos';
const err = $node[upsertNode]?.json?.error;
if (err) { return []; }
const upserted = ($items(upsertNode) || []).filter((i) => {
  const j = i?.json || {};
  if (!j || j._skip || j.error) return false;
  if (j.success === true && Object.keys(j).length === 1) return false;
  return Object.keys(j).length > 0;
}).length;
if (upserted === 0) { return []; }
const companyName = $items('Build sync_state map')[0]?.json?.company || '';
return [{ json: { companyName, nowIso: new Date().toISOString() } }];

const upsertItems = $items('Upsert PS_Year');
if (!upsertItems.length) { return []; }
for (const it of upsertItems) {
  const j = it?.json || {};
  if (j.error) { return []; }
}
const companyName = $items('Build sync_state map')[0]?.json?.company || '';
return [{ json: { companyName, nowIso: new Date().toISOString() } }];

const upsertNode = 'Upsert Proyectos';
const err = $node[upsertNode]?.json?.error;
if (err) { return []; }
const upserted = ($items(upsertNode) || []).filter((i) => {
  const j = i?.json || {};
  if (!j || j._skip || j.error) return false;
  if (j.success === true && Object.keys(j).length === 1) return false;
  return Object.keys(j).length > 0;
}).length;
if (upserted === 0) { return []; }
const companyName = $items('Build sync_state map')[0]?.json?.company || '';
return [{ json: { companyName, nowIso: new Date().toISOString() } }];

const upsertNode = 'Upsert Equipo Proyectos';
const err = $node[upsertNode]?.json?.error;
if (err) { return []; }
const upserted = ($items(upsertNode) || []).filter((i) => {
  const j = i?.json || {};
  if (!j || j._skip || j.error) return false;
  if (j.success === true && Object.keys(j).length === 1) return false;
  return Object.keys(j).length > 0;
}).length;
if (upserted === 0) { return []; }
const companyName = $items('Build sync_state map')[0]?.json?.company || '';
return [{ json: { companyName, nowIso: new Date().toISOString() } }];

const batch = $('Parse Webhook Batch').first()?.json?.batch || { syncAll: true, enabledEntities: [] };
const p = $json.params || {};
const slugRaw = (p.company || $json.query?.company || batch.companyFromBody || '').toString().trim().toLowerCase();
const slug = encodeURI(slugRaw);
const map = {
  'psi': { companyName: 'Power Solution Iberia SL', companyId: 'ca9dc1bf-54ee-ed11-884a-000d3a455d5b' },
  'pslab': { companyName: 'PS LAB CONSULTING SL', companyId: '656f8f0e-2bf4-ed11-8848-000d3a4baf18' }
};
const chosen = map[slug];
if (!chosen) {
  return [{ json: { error: 'Invalid company', slug, batch } }];
}
return [{ json: { companyName: chosen.companyName, companyId: chosen.companyId, slug, batch } }];

const batch = $('Resolve Company').first()?.json?.batch || { syncAll: true, enabledEntities: [] };
const syncAll = batch.syncAll !== false && (!Array.isArray(batch.enabledEntities) || batch.enabledEntities.length === 0);
const enabledEntities = syncAll ? [] : (batch.enabledEntities || []);
const AGG = new Set(['job_planning_line','job_ledger_entry_month','expediente_mes','historico_planificacion_mes']);
const enabled = enabledEntities || [];
const needsJobFallback = !syncAll && enabled.includes('job') && enabled.some(k => AGG.has(k));
const rows = $input.all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]);
const entities = [
  'resource','ps_year','job','job_team','job_task',
  'centers_of_responsibility','user_configuration',
  'technologies','typologies','departments',
  'job_ledger_entry_month','job_planning_line',
