const parseBoolean = (value) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') {
    const v = value.trim().toLowerCase();
    if (['true', '1', 'yes', 'si', 'sí'].includes(v)) return true;
    if (['false', '0', 'no', ''].includes(v)) return false;
  }
  return false;
};

const resolveTimesheetBlocked = (row) => {
  const direct = [
    row.ARBVRNTimeSheetBlocked,
    row.arbvrnTimeSheetBlocked,
    row.ARBVRNTimesheetBlocked,
    row.timesheet_blocked,
    row.timesheetBlocked,
    row.timeSheetBlocked,
  ].find((v) => v !== undefined && v !== null);
  if (direct !== undefined) return parseBoolean(direct);
  for (const [key, value] of Object.entries(row || {})) {
    const normalized = String(key).toLowerCase();
    if (normalized.includes('timesheet') && normalized.includes('blocked')) {
      return parseBoolean(value);
    }
  }
  return false;
};

for (const r of registros) {
  const jobNo = String(r.job_no ?? r.jobNo ?? r.projectNo ?? '').trim();
  const taskNo = String(r.no ?? r.task_no ?? r.taskNo ?? '').trim();
  const description = String(r.description ?? '').trim() || 'Sin descripción';
  const timesheetBlocked = resolveTimesheetBlocked(r);

  if (!jobNo || !taskNo) continue;
  if (jobNo.startsWith('PP') || jobNo.startsWith('PY')) continue;

  items.push({ json: { companyName, jobNo, taskNo, description, timesheetBlocked } });
}

console.log(`✅ Transform ProyectosTareas: ${items.length} tareas de ${registros.length} totales`);
if (items.length === 0) {
  return [{ json: { _skip: true, reason: 'no_valid_job_tasks' } }];
}
return items;

const upsertNode = 'Upsert Job Task';
const err = $node[upsertNode]?.json?.error;
if (err) { return []; }
const upserted = ($items(upsertNode) || []).filter((i) => {
  const j = i?.json || {};
  if (!j || j._skip || j.error) return false;
  if (j.success === true && Object.keys(j).length === 1) return false;
  return Object.keys(j).length > 0;
}).length;
if (upserted === 0) { return []; }
const companyName = $items('Build sync_state map')[0]?.json?.company || '';
return [{ json: { companyName, nowIso: new Date().toISOString() } }];

const items = $input.all();
let failed = 0;
let firstErr = '';
for (const it of items) {
  const j = it?.json || {};
  const statusCode = Number(j?.statusCode ?? j?.response?.statusCode ?? 0);
  const bodyErr = j?.body?.error?.message || (typeof j?.body === 'string' ? j.body : null);
  const msg = j?.error?.message || j?.message || j?.data?.error || j?.response?.body || j?.responseBody || bodyErr || null;
  if (!firstErr && msg) firstErr = String(msg);
  if (msg || statusCode >= 400) failed++;
}
const success = items.length - failed;
const synced = success;
const res = { key: 'job_task', causeNode: 'Upsert Job Task' };
if (failed > 0) { res.status = 'error'; res.synced = success; res.failed = failed; res.message = firstErr || ('HTTP ' + (items[0]?.json?.statusCode || 'error')); } else { res.status = 'ok'; res.synced = synced; res.success = success; }
return [{ json: res }];

