    const pk = [
      jobNo, lineNo, year, month, budgetYear, budgetMonth,
      statusRaw, monthClosingStatus, typeLine, lineType, departamento,
      description, tipoProyecto, probability, doNotConsolidate, conceptoAnalitico,
    ].join('|');

