const fields = ["lastModifiedDateTime"]; // 1 campo: evita OOM n8n (3x ventanas)

const p = map.partition || {};
const sinceYear = Number(p.sinceYear) || new Date().getUTCFullYear() - 2;
const windowDays = Math.max(1, Number(p.windowDays) || 21);
const maxWindows = Math.max(1, Number(p.maxWindows) || 120);

