const start = startFromSync > minDate ? startFromSync : minDate;
const stepMs = windowDays * 24 * 60 * 60 * 1000;

const windows = [];
let cursor = new Date(start.getTime());
while (cursor < now && windows.length < maxWindows) {
  const end = new Date(Math.min(now.getTime(), cursor.getTime() + stepMs));
  windows.push({ start: new Date(cursor.getTime()), end });
  cursor = end;
}
if (!windows.length) {
  windows.push({ start, end: now });
}

