  out.push({
    json: {
      url: base + '?$filter=' + encodeURIComponent(map.aggregateJobBatchFilter) + '&$select=' + select,
      filterField: 'jobBatch',
      entityKey: 'job_planning_line',
      partitionKey: 'jobBatch',
